import React, { useState, useEffect, useMemo } from 'react';
import { Redirect, Route, Switch, useLocation } from 'react-router-dom';
import PropTypes from 'prop-types';
import {
  // getNews,
  // getNewsCategory,

// //   //getCategoryNews,
// //   getSearchNews,
} from '../../api/news';
import { HomePage } from '../HomePage';
import { ArticlesPage } from '../ArticlesPage';
import './Main.scss';

export const Main = ({ appliedQuery }) => {
  const [newsTrending, setNewsTrending] = useState([]);
  //const [news, setNews] = useState([]);
  const [newsCategory, setNewsCategory] = useState({});
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const category = searchParams.get('category');
  const [article, setArticle] = useState({});

  useEffect(() => {
    getNews().then(res => setNewsTrending(res.articles));
  }, []);

  useEffect(() => {
    if (!(category in newsCategory) && category) {
      getNewsCategory(category).then(res => setNewsCategory({
        ...newsCategory,
        [category]: res.articles,
      }));
    }
  }, [category]);

  const articles = useMemo((item) => {
    setArticle(item);
  }, [article]);

  console.log(location);
  console.log(category);
  console.log(newsTrending);
  console.log(newsCategory);
  console.log(`Ar-1: ${article}`);

  return (
    <div className="Main">
      <Switch>
        <Route path="/articles">
          <ArticlesPage
            article={article}
            appliedQuery={appliedQuery}
            newsTrending={newsTrending}
            newsCategory={newsCategory[category]}
          />
        </Route>
        <Route path="/home/:par?">
          <HomePage
            newsTrending={newsTrending}
            newsCategory={newsCategory[category]}
            setArticle={articles}
            appliedQuery={appliedQuery}
          />
        </Route>
        <Redirect path="/" to="/home" />
      </Switch>
    </div>
  );
};

Main.propTypes = {
  appliedQuery: PropTypes.string.isRequired,

};
